  ('flow.list.export-to-markdown', '[{"step_kind":"setup","description":"Open a document that contains a list block.","user_visible_outcome":"The document has exportable content."},{"step_kind":"action","action_kind":"click","description":"Export the document to Markdown."},{"step_kind":"assert","description":"The list block is rendered correctly in the Markdown output.","user_visible_outcome":"The exported Markdown contains the list’s content."}]'::jsonb),
  ('flow.list.convert-via-slash', '[{"step_kind":"setup","description":"Open a document in the Flow editor. with a paragraph to convert.","user_visible_outcome":"The continuous-prose canvas is ready."},{"step_kind":"action","action_kind":"click","description":"Click into the block you want to convert."},{"step_kind":"action","action_kind":"type","description":"Type a forward slash to open the slash command menu."},{"step_kind":"action","action_kind":"click","description":"Choose the list command."},{"step_kind":"assert","description":"The block is converted to a list.","user_visible_outcome":"The block is now a list; its content is preserved."}]'::jsonb),
  ('flow.paragraph.create-via-slash', '[{"step_kind":"setup","description":"Open a document in the Flow editor.","user_visible_outcome":"The continuous-prose canvas is ready."},{"step_kind":"action","action_kind":"click","description":"Click into the canvas to place the cursor."},{"step_kind":"action","action_kind":"type","description":"Type a forward slash to open the slash command menu.","user_visible_outcome":"The slash command menu lists the block types."},{"step_kind":"action","action_kind":"click","description":"Filter to \"paragraph\" and choose the paragraph command."},{"step_kind":"assert","description":"A paragraph block is created.","user_visible_outcome":"A new paragraph block appears in the Flow editor."}]'::jsonb),
