  ('flow.table.export-to-markdown', '[{"step_kind":"setup","description":"Open a document that contains a table block.","user_visible_outcome":"The document has exportable content."},{"step_kind":"action","action_kind":"click","description":"Export the document to Markdown."},{"step_kind":"assert","description":"The table block is rendered correctly in the Markdown output.","user_visible_outcome":"The exported Markdown contains the table’s content."}]'::jsonb),
  ('flow.pageBreak.export-to-latex', '[{"step_kind":"setup","description":"Open a document that contains a page break block.","user_visible_outcome":"The document has exportable content."},{"step_kind":"action","action_kind":"click","description":"Export the document to LaTeX."},{"step_kind":"assert","description":"The page break block is rendered correctly in the LaTeX output.","user_visible_outcome":"The exported LaTeX contains the page break’s markup."}]'::jsonb),
  ('flow.pageBreak.reorder-via-drag', '[{"step_kind":"setup","description":"Open a document in the Flow editor with a page break block and at least one other block.","user_visible_outcome":"The continuous-prose canvas is ready."},{"step_kind":"action","action_kind":"click","description":"Hover the page break block to reveal its drag handle."},{"step_kind":"action","action_kind":"click","description":"Drag the page break block to a new position."},{"step_kind":"assert","description":"The page break block moves to the new position.","user_visible_outcome":"The document order reflects the move."}]'::jsonb),
